SELECT COUNT(A.DOCID) FROM TBAPRRECEIPTPROCESSINFO A INNER JOIN TBAPRDOCINFO B ON A.TENANT_ID = B.TENANT_ID AND A.COMPANYID = B.COMPANYID AND A.DOCID = B.DOCID INNER JOIN TBEXPAPRDOCINFO C ON C.TENANT_ID = B.TENANT_ID AND C.COMPANYID = B.COMPANYID AND C.DOCID = B.DOCID WHERE A.TENANT_ID = #tenantID# AND A.COMPANYID = #companyID# AND A.PROCESSYN <> 'Y' AND (((A.PROCESSORID = #userID#) AND (A.APRSTATE = #staASJiJung# OR A.APRSTATE = #staASWheSong#))
(A.ReceivedDeptID = #userDeptID# AND A.AprState IN (#staASDoJak#, #staASBaeBu#)) OR (A.ReceivedDeptID = #userDeptID# AND A.AprState = #staASWheSong#)
)
